const numbersToWords=a=>{const V=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(a<0x14)return V[a];if(a<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](a/0xa)]+(a%0xa?'\x20'+V[a%0xa]:'');if(a<0x3e8){const s=Math['floor'](a/0x64),W=a%0x64;return(0x1===s?'εκατό':0x2===s?'διακόσια':0x3===s?'τριακόσια':0x4===s?'τετρακόσια':0x5===s?'πεντακόσια':0x6===s?'εξακόσια':0x7===s?'επτακόσια':0x8===s?'οκτακόσια':0x9===s?'εννιακόσια':'')+(W?'\x20'+numbersToWords(W):'');}return a<0xf4240?numbersToWords(Math['floor'](a/0x3e8))+'\x20χιλιάδες'+(a%0x3e8?'\x20'+numbersToWords(a%0x3e8):''):numbersToWords(Math['floor'](a/0xf4240))+'\x20εκατομμύρια'+(a%0xf4240?'\x20'+numbersToWords(a%0xf4240):'');},numberToText=(a,V='money')=>{const W=Math['floor'](a),A=Math['round'](0x64*(a-W));let c=numbersToWords(W),G=A>0x0?numbersToWords(A):'';switch(V){case'money':return G?c+'\x20ευρώ\x20και\x20'+G+'\x20λεπτά':c+'\x20ευρώ';case'time':return G?c+'\x20ώρες\x20και\x20'+G+'\x20λεπτά':c+'\x20ώρες';default:return G?c+'\x20και\x20'+G:''+c;}};